{
  "schemaVersion": 2,
  "id": "forest-dawn-pack",
  "name": "Forest Dawn Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "theme-pack",
  "capabilities": [
    "theme.style"
  ],
  "platforms": [
    "desktop",
    "web"
  ],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [
        {
          "file": "theme/style/forest-dawn-pack.css",
          "label": "Forest Dawn",
          "description": "Forest-inspired light/dark palette with gradient accents."
        }
      ],
      "snippets": [],
      "tokens": [],
      "defaultEnable": {
        "style": false
      }
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * Forest Dawn — external CSS theme
 *
 * Warm light theme with moss green and soft wood tones.
 * Layer: palette tokens + personality deltas only.
 *
 * Copy to ~/.luna/theme/style/forest-dawn.css → Rescan → Preferences → Appearance → External CSS tab.
 * Reference: docs/theme-example/SELECTORS.md
 */

html[data-theme='light'] {
  --surface-app: #eef3ea;
  --surface-panel: rgba(252, 250, 245, 0.95);
  --surface-editor: #fcfaf5;
  --surface-preview: #f8f6f0;
  --surface-hover: rgba(74, 103, 65, 0.07);
  --surface-elevated: #ffffff;
  --text-primary: #2c3328;
  --text-secondary: #5a6354;
  --text-muted: #8a9484;
  --text-tertiary: #8a9484;
  --border-subtle: rgba(44, 51, 40, 0.1);
  --border-strong: rgba(44, 51, 40, 0.18);
  --accent: #4a6741;
  --link: #3d7a52;
  --link-hover: #2f6240;
  --link-visited: #6b7c3e;
  --focus-ring: rgba(74, 103, 65, 0.22);
  --code-bg: #f4f2eb;
  --code-gutter-fg: #8a9484;
  --code-gutter-bg: #eef3ea;
  --inline-code-bg: #e8ede3;
  --shadow-soft: 0 1px 2px rgba(44, 51, 40, 0.06);
  --shadow-panel: 0 10px 32px rgba(44, 51, 40, 0.08);
  --luna-callout-tip: #3d7a52;
}

html[data-theme='dark'] {
  --surface-app: #1a2118;
  --surface-panel: rgba(28, 36, 26, 0.96);
  --surface-editor: #1e271c;
  --surface-preview: #171d15;
  --surface-hover: rgba(143, 188, 127, 0.1);
  --surface-elevated: #243020;
  --text-primary: #dce8d4;
  --text-secondary: #a8b89e;
  --text-muted: #6d7a66;
  --text-tertiary: #6d7a66;
  --border-subtle: rgba(220, 232, 212, 0.08);
  --border-strong: rgba(220, 232, 212, 0.14);
  --accent: #8fbc7f;
  --link: #8fbc7f;
  --link-hover: #a8d498;
  --link-visited: #b8c97a;
  --focus-ring: rgba(143, 188, 127, 0.24);
  --code-bg: #171d15;
  --code-gutter-fg: #6d7a66;
  --code-gutter-bg: #1a2118;
  --inline-code-bg: #2a3526;
  --shadow-soft: 0 1px 3px rgba(0, 0, 0, 0.45);
  --shadow-panel: 0 12px 40px rgba(0, 0, 0, 0.52);
  --luna-callout-tip: #8fbc7f;
}

html[data-theme='light'] .workspace-root {
  background:
    radial-gradient(ellipse 85% 55% at 50% -10%, rgba(74, 103, 65, 0.08), transparent 60%),
    var(--surface-app);
}

.sidebar {
  background: color-mix(in srgb, var(--surface-panel) 88%, var(--accent) 4%);
  border-right: 1px solid color-mix(in srgb, var(--accent) 14%, var(--border-subtle));
}

.preview-pane.markdown-visual-editor .ProseMirror,
.markdown-preview-view {
  line-height: 1.78;
}

.preview-pane.markdown-visual-editor .ProseMirror .pm-heading-block--l1 .pm-heading-content,
.preview-pane.markdown-visual-editor .ProseMirror > h1,
.markdown-preview-view h1 {
  color: var(--accent);
  font-weight: 600;
  letter-spacing: -0.015em;
}

.preview-pane.markdown-visual-editor .ProseMirror .pm-heading-block--l2 .pm-heading-content,
.preview-pane.markdown-visual-editor .ProseMirror > h2,
.markdown-preview-view h2 {
  color: var(--accent);
  font-weight: 600;
  padding-left: 0.65em;
  border-left: 3px solid color-mix(in srgb, var(--accent) 55%, transparent);
}

/* Themed HR — accent-tinted gradient */
.preview-pane.markdown-visual-editor .ProseMirror hr,
.markdown-preview-view hr {
  background: linear-gradient(
    90deg,
    transparent,
    color-mix(in srgb, var(--accent) 35%, transparent),
    transparent
  );
}

.preview-pane.markdown-visual-editor .ProseMirror > blockquote,
.markdown-preview-view blockquote {
  border-left: 3px solid var(--accent);
  background: color-mix(in srgb, var(--accent) 6%, var(--surface-editor));
  border-radius: 0 10px 10px 0;
  padding: 0.5em 1em;
  color: var(--text-secondary);
}
